struct TreapNode {
    key: i32,
    priority: u64,
    left: Option<Box<TreapNode>>,
    right: Option<Box<TreapNode>>,
}

static mut SEED: u64 = 12345;

fn next_rand() -> u64 {
    unsafe {
        SEED ^= SEED << 13;
        SEED ^= SEED >> 7;
        SEED ^= SEED << 17;
        SEED
    }
}

impl TreapNode {
    fn new(key: i32) -> Self {
        TreapNode {
            key,
            priority: next_rand(),
            left: None,
            right: None,
        }
    }
}

fn right_rot(mut p: Box<TreapNode>) -> Box<TreapNode> {
    let mut q = p.left.take().unwrap();
    p.left = q.right.take();
    q.right = Some(p);
    q
}

fn left_rot(mut p: Box<TreapNode>) -> Box<TreapNode> {
    let mut q = p.right.take().unwrap();
    p.right = q.left.take();
    q.left = Some(p);
    q
}

fn insert_node(root: Option<Box<TreapNode>>, key: i32) -> Box<TreapNode> {
    match root {
        None => Box::new(TreapNode::new(key)),
        Some(mut node) => {
            if key < node.key {
                node.left = Some(insert_node(node.left.take(), key));
                if node.left.as_ref().unwrap().priority > node.priority {
                    node = right_rot(node);
                }
            } else if key > node.key {
                node.right = Some(insert_node(node.right.take(), key));
                if node.right.as_ref().unwrap().priority > node.priority {
                    node = left_rot(node);
                }
            }
            node
        }
    }
}

fn inorder_collect(node: &Option<Box<TreapNode>>, result: &mut Vec<i32>) {
    if let Some(ref n) = node {
        inorder_collect(&n.left, result);
        result.push(n.key);
        inorder_collect(&n.right, result);
    }
}

pub fn treap(arr: &[i32]) -> Vec<i32> {
    let mut root: Option<Box<TreapNode>> = None;
    for &val in arr {
        root = Some(insert_node(root, val));
    }
    let mut result = Vec::new();
    inorder_collect(&root, &mut result);
    result
}

object Treap {
  private val rng = new scala.util.Random(42)

  private class TNode(val key: Int, val priority: Int = rng.nextInt()) {
    var left: TNode = null
    var right: TNode = null
  }

  private def rightRot(p: TNode): TNode = {
    val q = p.left
    p.left = q.right
    q.right = p
    q
  }

  private def leftRot(p: TNode): TNode = {
    val q = p.right
    p.right = q.left
    q.left = p
    q
  }

  private def insertNode(root: TNode, key: Int): TNode = {
    if (root == null) return new TNode(key)
    var node = root
    if (key < node.key) {
      node.left = insertNode(node.left, key)
      if (node.left.priority > node.priority) node = rightRot(node)
    } else if (key > node.key) {
      node.right = insertNode(node.right, key)
      if (node.right.priority > node.priority) node = leftRot(node)
    }
    node
  }

  private def inorderCollect(node: TNode, result: scala.collection.mutable.ArrayBuffer[Int]): Unit = {
    if (node == null) return
    inorderCollect(node.left, result)
    result += node.key
    inorderCollect(node.right, result)
  }

  def treap(arr: Array[Int]): Array[Int] = {
    var root: TNode = null
    for (v <- arr) root = insertNode(root, v)
    val result = scala.collection.mutable.ArrayBuffer[Int]()
    inorderCollect(root, result)
    result.toArray
  }
}

private class TreapNode {
    var key: Int
    var priority: Int
    var left: TreapNode?
    var right: TreapNode?
    init(_ key: Int) {
        self.key = key
        self.priority = Int.random(in: 0..<Int.max)
        self.left = nil
        self.right = nil
    }
}

private func rightRot(_ p: TreapNode) -> TreapNode {
    let q = p.left!
    p.left = q.right
    q.right = p
    return q
}

private func leftRot(_ p: TreapNode) -> TreapNode {
    let q = p.right!
    p.right = q.left
    q.left = p
    return q
}

private func insertNode(_ root: TreapNode?, _ key: Int) -> TreapNode {
    guard var node = root else { return TreapNode(key) }
    if key < node.key {
        node.left = insertNode(node.left, key)
        if node.left!.priority > node.priority { node = rightRot(node) }
    } else if key > node.key {
        node.right = insertNode(node.right, key)
        if node.right!.priority > node.priority { node = leftRot(node) }
    }
    return node
}

private func inorderCollect(_ node: TreapNode?, _ result: inout [Int]) {
    guard let node = node else { return }
    inorderCollect(node.left, &result)
    result.append(node.key)
    inorderCollect(node.right, &result)
}

func treap(_ arr: [Int]) -> [Int] {
    var root: TreapNode? = nil
    for val in arr { root = insertNode(root, val) }
    var result: [Int] = []
    inorderCollect(root, &result)
    return result
}

class TreapNode {
    key: number;
    priority: number;
    left: TreapNode | null = null;
    right: TreapNode | null = null;
    constructor(key: number) {
        this.key = key;
        this.priority = Math.floor(Math.random() * 2147483647);
    }
}

function rightRot(p: TreapNode): TreapNode {
    const q = p.left!;
    p.left = q.right;
    q.right = p;
    return q;
}

function leftRot(p: TreapNode): TreapNode {
    const q = p.right!;
    p.right = q.left;
    q.left = p;
    return q;
}

function insertTreapNode(root: TreapNode | null, key: number): TreapNode {
    if (!root) return new TreapNode(key);
    if (key < root.key) {
        root.left = insertTreapNode(root.left, key);
        if (root.left!.priority > root.priority) root = rightRot(root);
    } else if (key > root.key) {
        root.right = insertTreapNode(root.right, key);
        if (root.right!.priority > root.priority) root = leftRot(root);
    }
    return root;
}

function inorderTreap(node: TreapNode | null, result: number[]): void {
    if (!node) return;
    inorderTreap(node.left, result);
    result.push(node.key);
    inorderTreap(node.right, result);
}

export function treap(arr: number[]): number[] {
    let root: TreapNode | null = null;
    for (const val of arr) root = insertTreapNode(root, val);
    const result: number[] = [];
    inorderTreap(root, result);
    return result;
}
